oxy_webhelp_navlinks = {"notifications-d30753e54742":{"topics":[{"title":"Emails","shortdesc":"<p class=\"shortdesc\">Email notifications in <span class=\"ph\">RSC<\/span> notify users about events, such as backup,         recovery, anomaly detection, and so on.<\/p>","href":"saas\/emails.html","attributes":{"data-id":"emails"},"menu":{"hasChildren":false},"tocID":"emails-d30753e54753","next":"emails-d30753e54753"},{"title":"Webhooks","shortdesc":"<p class=\"shortdesc\">Webhook integration sends event details related to a service account from         <span class=\"ph\">RSC<\/span> to external systems. This makes it easier to monitor and analyze logs         for security incidents while keeping control over data transmission.<\/p>","href":"saas\/common\/webhooks.html","attributes":{"data-id":"webhooks"},"menu":{"hasChildren":false},"tocID":"webhooks-d30753e54795","next":"webhooks-d30753e54795"},{"title":"SNMP integration","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> uses Simple Network Management Protocol integration for central         monitoring of managed devices on IP networks. Simple Network Management Protocol  is a         protocol for collecting and organizing information about managed devices on IP         networks.<\/p>","href":"saas\/snmp_integration.html","attributes":{"data-id":"snmp_integration"},"menu":{"hasChildren":false},"tocID":"snmp_integration-d30753e55001","next":"snmp_integration-d30753e55001"},{"title":"Syslog protocol","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster supports transmission of system activities to an external syslog     server using standard syslog protocol.<\/p>","href":"cdm_old\/syslog_settings.html","attributes":{"data-id":"syslog_settings"},"menu":{"hasChildren":false},"tocID":"syslog_settings-d30753e55080","next":"syslog_settings-d30753e55080"}]}};